#!/usr/bin/env python3
"""Verify the frozen Stage 3-D Gate 1 design authority after later gates advance."""
from __future__ import annotations
import hashlib,json,subprocess,sys
from collections import Counter
from pathlib import Path
ROOT=Path(__file__).resolve().parents[2]; EXP=Path(__file__).resolve().parent
load=lambda p: json.loads((EXP/p).read_text()); text=lambda p:(ROOT/p).read_text()
a=load('gate1-consumer-authority.json'); m=load('gate2-consumer-discovery-matrix.json'); rows=m['scenarios']; checks={}
def ck(k,v): checks[k]=bool(v)
ck('authority_schema',a['schema_version']==1); ck('authority_kind',a['authority_kind']=='stage3d-gate1-consumer-authority-design'); ck('authority_status',a['status']=='design-frozen'); ck('authority_model',a['primary_model']=='uv-system-python'); ck('authority_control',a['canonical_control']=='explicit-absolute-interpreter-path')
ck('gate4_commit',a['input_authority']['gate4e_commit']=='68b67dcc3b65872e1034c487747d3fcd1ad5a319'); ck('gate4_tree',a['input_authority']['gate4e_tree']=='2115f6fa3b923c9fcf21a1b8343cb6149afb6cc7'); ck('gate4_66',a['input_authority']['gate4_scenarios']=={'count':66,'pass':66})
ck('products',[p['python'] for p in a['products']]==['3.14.5','3.14.6']); ck('topologies',a['topologies']==['runtime-only','runtime+development','runtime+test','full']); ck('download_policy',a['download_policy']=='disabled-for-all-system-integration-scenarios')
for item in ('global-prefix-links','shell-startup-edits','managed-install-dir-registration','uv-patching','python-download-fallback','root','proot','shizuku','docker'): ck('forbidden_'+item,item in a['mutation_policy']['forbidden'])
ck('matrix_schema',m['schema_version']==1); ck('matrix_kind',m['matrix_kind']=='stage3d-gate2-consumer-discovery-census'); ck('matrix_design_status',m['status']=='design-frozen-not-executed'); ck('matrix_count',m['scenario_count']==64 and len(rows)==64); ck('matrix_unique',len({r['id'] for r in rows})==64)
ck('matrix_groups',Counter(r['group'] for r in rows)==Counter({'explicit':8,'natural':32,'project':8,'precedence-negative':12,'transition-continuity':4})); ck('matrix_products',all({r['product'] for r in rows if r['group']==g}=={'3.14.5','3.14.6'} for g in ('explicit','natural','project'))); ck('matrix_topologies',all({r['topology'] for r in rows if r['group']==g}=={'runtime-only','runtime+development','runtime+test','full'} for g in ('explicit','natural','project')))
ck('matrix_requirements',all(x in m['global_requirements'] for x in ('python-downloads-disabled','raw-stdout-stderr-exit-recorded','selected-realpath-recorded','repository-invariant','canonical-installation-invariant','pass-or-fail-archive-preserved')))
# Later gates may advance current docs; they must preserve Gate 1 as frozen and reference its authority.
ctx=text('docs/PROJECT_CONTEXT_STAGE3D.md'); scope=text('docs/stages/STAGE3D_SCOPE.md'); readme=text('README.md'); handoff=text('docs/handoff/README.md'); orient=text('docs/PROJECT_ORIENTATION.md')
ck('current_gate1_frozen','Gate 1  scope and authority design             FROZEN' in ctx); ck('scope_gate1_frozen','Gate 1  scope and consumer authority design             FROZEN' in scope); ck('handoff_gate1_frozen','Stage 3-D Gate 1 authority design                       FROZEN' in handoff); ck('readme_stage3d_current','Stage 3-D  consumer integration' in readme); ck('orientation_current','docs/PROJECT_CONTEXT_STAGE3D.md' in orient)
required=['experiments/stage3d-consumer-integration/GATE1_CONSUMER_AUTHORITY_DESIGN.md','experiments/stage3d-consumer-integration/gate1-consumer-authority.json','experiments/stage3d-consumer-integration/gate2-consumer-discovery-matrix.json','docs/evidence/STAGE3D_GATE1_CONSUMER_AUTHORITY_DESIGN_RESULT.md']
ck('required_paths',all((ROOT/p).is_file() for p in required)); ck('git_diff_check',subprocess.run(['git','-C',str(ROOT),'diff','--check','HEAD'],stdout=subprocess.PIPE,stderr=subprocess.PIPE).returncode==0); ck('python_compile',subprocess.run([sys.executable,'-m','py_compile',str(Path(__file__))],stdout=subprocess.PIPE,stderr=subprocess.PIPE).returncode==0)
failed=sorted(k for k,v in checks.items() if not v); out={'schema_version':1,'verification_kind':'stage3d-gate1-consumer-authority-design-verification','pass':not failed,'check_count':len(checks),'pass_count':sum(checks.values()),'failed_checks':failed,'checks':dict(sorted(checks.items())),'observed':{'authority_sha256':hashlib.sha256((EXP/'gate1-consumer-authority.json').read_bytes()).hexdigest(),'matrix_sha256':hashlib.sha256((EXP/'gate2-consumer-discovery-matrix.json').read_bytes()).hexdigest(),'scenario_count':len(rows),'tree_before_commit':subprocess.check_output(['git','-C',str(ROOT),'write-tree'],text=True).strip()},'claim_boundary':'Verifies the preserved Gate 1 design authority; later target and contract acceptance is outside this verifier.'}
print(json.dumps(out,indent=2,sort_keys=True)); print(); print(f"STAGE3D_GATE1_CONSUMER_AUTHORITY_DESIGN_VERIFICATION={out['pass_count']}/{out['check_count']} {'PASS' if out['pass'] else 'FAIL'}"); raise SystemExit(0 if out['pass'] else 1)
